import styled from "styled-components";
import Header from "smart-react-components/element/Header";
export default styled(Header).attrs(({ justifyContent = "space-between" }) => ({
    justifyContent
}))(({ theme }) => `
    display: flex;
    flex-wrap: wrap;
    border-bottom: solid 1px ${theme.src.color.gray_300};

    > * {
        margin: 0 1px;
    }
`);
